module top_module(
    input  [3:0] D,
    input  S0,
    input  S1,
    output Y
);reg [1:0] invalid_sel;

    always @ (S0 or S1) begin
        case ({S1, S0})
            2'b00: invalid_sel = 2'b00;
            2'b01: invalid_sel = 2'b01;
            2'b10: invalid_sel = 2'b10;
            2'b11: invalid_sel = 2'b11;
        endcase
    end

    assign Y = D[invalid_sel];

endmodule
